import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { violationsAPI } from '../../services/api';
import Card from '../../components/common/Card';
import { FileText, AlertTriangle, Loader2, Calendar, CheckCircle, Clock } from 'lucide-react';

const StudentViolations = () => {
  const { user } = useAuth();
  const [violations, setViolations] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchViolations();
  }, []);

  const fetchViolations = async () => {
    try {
      // Get violations for current student using user ID from JWT
      const response = await violationsAPI.getByUserId(user.id);
      if (response.data.success) {
        setViolations(response.data.violations);
      }
    } catch (error) {
      console.error('Error fetching violations:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="w-10 h-10 animate-spin text-orange-600" />
      </div>
    );
  }

  const pendingCount = violations.filter(v => v.status === 'Pending').length;
  const resolvedCount = violations.filter(v => v.status === 'Resolved').length;

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header */}
      <div className="bg-gradient-to-r from-orange-500 via-orange-600 to-orange-700 rounded-2xl p-6 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2"></div>
        <div className="relative z-10">
          <div className="flex items-center gap-2 text-orange-200 mb-1">
            <AlertTriangle className="w-4 h-4" />
            <span className="text-sm font-medium">Disciplinary Records</span>
          </div>
          <h1 className="text-2xl font-bold">My Violations</h1>
          <div className="flex gap-6 mt-3">
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 bg-yellow-300 rounded-full"></div>
              <span className="text-orange-100 text-sm">{pendingCount} Pending</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 bg-green-300 rounded-full"></div>
              <span className="text-orange-100 text-sm">{resolvedCount} Resolved</span>
            </div>
          </div>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
        <div className="card-hover">
          <Card>
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 bg-gradient-to-br from-secondary-400 to-secondary-600 rounded-xl flex items-center justify-center shadow-lg">
                <FileText className="w-7 h-7 text-white" />
              </div>
              <div>
                <p className="text-sm text-secondary-500">Total Violations</p>
                <p className="text-2xl font-bold text-secondary-800">{violations.length}</p>
              </div>
            </div>
          </Card>
        </div>
        <div className="card-hover">
          <Card>
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 bg-gradient-to-br from-yellow-400 to-yellow-600 rounded-xl flex items-center justify-center shadow-lg">
                <Clock className="w-7 h-7 text-white" />
              </div>
              <div>
                <p className="text-sm text-secondary-500">Pending</p>
                <p className="text-2xl font-bold text-yellow-600">{pendingCount}</p>
              </div>
            </div>
          </Card>
        </div>
        <div className="card-hover">
          <Card>
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 bg-gradient-to-br from-green-400 to-green-600 rounded-xl flex items-center justify-center shadow-lg">
                <CheckCircle className="w-7 h-7 text-white" />
              </div>
              <div>
                <p className="text-sm text-secondary-500">Resolved</p>
                <p className="text-2xl font-bold text-green-600">{resolvedCount}</p>
              </div>
            </div>
          </Card>
        </div>
      </div>

      {/* Violations List */}
      <Card title="Violation Records" icon={AlertTriangle}>
        {violations.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="table-modern">
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Violation Type</th>
                  <th>Status</th>
                  <th>Remarks</th>
                </tr>
              </thead>
              <tbody>
                {violations.map((violation) => (
                  <tr key={violation.id}>
                    <td>
                      <div className="flex items-center gap-2 text-secondary-600">
                        <Calendar className="w-4 h-4 text-secondary-400" />
                        {violation.date}
                      </div>
                    </td>
                    <td>
                      <span className={`inline-flex items-center gap-1.5 font-medium ${
                        violation.violation_type.includes('Major') ? 'text-red-600' : 'text-orange-600'
                      }`}>
                        <AlertTriangle className="w-4 h-4" />
                        {violation.violation_type}
                      </span>
                    </td>
                    <td>
                      <span className={`badge ${
                        violation.status === 'Pending' ? 'badge-warning' : 'badge-success'
                      }`}>
                        {violation.status}
                      </span>
                    </td>
                    <td className="text-secondary-600">{violation.remarks || '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="empty-state py-16">
            <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <CheckCircle className="w-10 h-10 text-green-500" />
            </div>
            <h3 className="text-lg font-semibold text-secondary-700 mb-2">No Violations Recorded</h3>
            <p className="text-secondary-500">You have a clean disciplinary record. Keep it up!</p>
          </div>
        )}
      </Card>
    </div>
  );
};

export default StudentViolations;
